import{_ as t,o,c as r,ae as d}from"./chunks/framework.BtCEPByy.js";const u=JSON.parse('{"title":"Runner & Provider Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/developer-reference.md","filePath":"guide/developer-reference.md"}'),a={name:"guide/developer-reference.md"};function i(s,e,n,l,h,c){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="runner-provider-guide" tabindex="-1">Runner &amp; Provider Guide <a class="header-anchor" href="#runner-provider-guide" aria-label="Permalink to &quot;Runner &amp; Provider Guide&quot;">​</a></h1><p>When you assign a task in Flowy, you are really choosing three things:</p><ol><li>Which machine should run it</li><li>Which AI CLI should handle it</li><li>Which harness settings should be passed through</li></ol><p>This page helps you make those choices quickly and safely.</p><h2 id="step-1-choose-the-right-runner" tabindex="-1">Step 1: Choose the right runner <a class="header-anchor" href="#step-1-choose-the-right-runner" aria-label="Permalink to &quot;Step 1: Choose the right runner&quot;">​</a></h2><p>Pick the machine that has the right environment for the job.</p><p>Use the runner card to check:</p><ul><li>whether it is <code>online</code>, <code>busy</code>, or <code>offline</code></li><li>which providers it currently detects</li><li>whether it is the machine that has the repo or files you want to target</li></ul><p>Use clear runner names so assignment stays obvious later.</p><p>Good examples:</p><ul><li><code>office-mac</code></li><li><code>mac-mini</code></li><li><code>gpu-linux</code></li><li><code>build-box</code></li></ul><h2 id="step-2-choose-the-provider" tabindex="-1">Step 2: Choose the provider <a class="header-anchor" href="#step-2-choose-the-provider" aria-label="Permalink to &quot;Step 2: Choose the provider&quot;">​</a></h2><p>Flowy only shows providers that the selected runner detected locally.</p><table tabindex="0"><thead><tr><th>Provider</th><th>Local CLI</th><th>Best when you want</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>claude</code></td><td>Claude Code workflows with workspace, model, mode, and worktree controls</td></tr><tr><td>Codex</td><td><code>codex</code></td><td>Codex execution with explicit workspace, model, and sandbox control</td></tr><tr><td>Cursor Agent</td><td><code>agent</code></td><td>Cursor Agent workflows with mode, sandbox, and optional worktree settings</td></tr></tbody></table><p>If the provider you want is missing:</p><ol><li>Make sure the CLI is installed on that machine.</li><li>Restart the runner or refresh its detected CLIs from the <code>Runners</code> page.</li><li>Reopen the assignment dialog.</li></ol><h2 id="step-3-set-the-workspace-first" tabindex="-1">Step 3: Set the workspace first <a class="header-anchor" href="#step-3-set-the-workspace-first" aria-label="Permalink to &quot;Step 3: Set the workspace first&quot;">​</a></h2><p>The <code>workspace</code> field matters more than anything else because it tells the CLI where to run.</p><ul><li>The path must exist on the runner machine.</li><li>The path should point at the repo or folder the AI needs to work in.</li><li>If the runner is remote, use that machine&#39;s local path, not the path from your laptop.</li></ul><p>If you are not sure what else to fill in, start with <code>workspace</code> and add the rest only when needed.</p><h2 id="step-4-add-provider-specific-settings" tabindex="-1">Step 4: Add provider-specific settings <a class="header-anchor" href="#step-4-add-provider-specific-settings" aria-label="Permalink to &quot;Step 4: Add provider-specific settings&quot;">​</a></h2><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><p>Use these fields when the runner is using Claude Code:</p><table tabindex="0"><thead><tr><th>Field</th><th>What it controls</th></tr></thead><tbody><tr><td><code>workspace</code></td><td>Working directory for the command</td></tr><tr><td><code>model</code></td><td>Model selection, such as <code>sonnet</code></td></tr><tr><td><code>mode</code></td><td>Claude Code execution mode</td></tr><tr><td><code>worktree</code></td><td>Optional worktree name</td></tr></tbody></table><h3 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h3><p>Use these fields when the runner is using Codex:</p><table tabindex="0"><thead><tr><th>Field</th><th>What it controls</th></tr></thead><tbody><tr><td><code>workspace</code></td><td>Working directory for <code>codex exec</code></td></tr><tr><td><code>model</code></td><td>Model selection, such as <code>gpt-5.4</code></td></tr><tr><td><code>sandbox</code></td><td>Execution sandbox: <code>read-only</code>, <code>workspace-write</code>, or <code>danger-full-access</code></td></tr></tbody></table><p>If you leave the Codex sandbox empty, Flowy uses <code>workspace-write</code>.</p><h3 id="cursor-agent" tabindex="-1">Cursor Agent <a class="header-anchor" href="#cursor-agent" aria-label="Permalink to &quot;Cursor Agent&quot;">​</a></h3><p>Use these fields when the runner is using Cursor Agent:</p><table tabindex="0"><thead><tr><th>Field</th><th>What it controls</th></tr></thead><tbody><tr><td><code>workspace</code></td><td>Working directory for the task</td></tr><tr><td><code>model</code></td><td>Model selection</td></tr><tr><td><code>mode</code></td><td>Agent mode, such as <code>plan</code> or <code>ask</code></td></tr><tr><td><code>sandbox</code></td><td>Sandbox behavior</td></tr><tr><td><code>worktree</code></td><td>Optional worktree name</td></tr></tbody></table><h2 id="step-5-monitor-task-and-runner-status" tabindex="-1">Step 5: Monitor task and runner status <a class="header-anchor" href="#step-5-monitor-task-and-runner-status" aria-label="Permalink to &quot;Step 5: Monitor task and runner status&quot;">​</a></h2><p>After you assign a task:</p><ol><li>The runner polls for work.</li><li>The task moves to <code>in_progress</code> when the runner picks it up.</li><li>The runner shows <code>busy</code> during execution.</li><li>Output streams into the task detail view.</li><li>The task finishes as <code>done</code> or <code>failed</code>.</li></ol><p>The <code>Inbox</code> page is the fastest way to monitor active work across every project.</p><h2 id="practical-tips" tabindex="-1">Practical tips <a class="header-anchor" href="#practical-tips" aria-label="Permalink to &quot;Practical tips&quot;">​</a></h2><ul><li>Keep runner names stable so past task history stays easy to read.</li><li>Keep task titles short and put details in the description.</li><li>Keep harness settings minimal. More fields only help when they are intentional.</li><li>Reassign failed work with better context instead of creating duplicate tasks when the original history still matters.</li></ul>',37)])])}const m=t(a,[["render",i]]);export{u as __pageData,m as default};
